  return new Intl.NumberFormat('en-US', {
    style: 'currency',
    currency: 'USD',
    maximumFractionDigits: 0
  }).format(value);
}

function formatTimestamp(value: string) {
  return new Intl.DateTimeFormat('en-US', {
    dateStyle: 'medium',
    timeStyle: 'short',
    timeZone: 'UTC'
  }).format(new Date(value));
}

function badgeTone(availability: string) {
  switch (availability) {
    case 'In stock':
      return { background: '#d9fbe6', color: '#166534' };
    case 'Low stock':
      return { background: '#fff2cc', color: '#92400e' };
    default:
      return { background: '#fee2e2', color: '#991b1b' };
  }
}

